// Q2 א - START
public static bool IsMirror(int[] arr)
{
// בדיקה ראשונית: אורך זוגי - לא חובה ,זה יעילות
if (arr.Length % 2 != 0)
return false;
// לולאה העוברת על כל איברי המערך
for (int i = 0; i < arr.Length; i++)
{
int target = -arr[i]; // המספר הנגדי שאנו מחפשים
bool found = false;
// לולאה פנימית לחיפוש המספר הנגדי במערך
for (int j = 0; j < arr.Length && found == false; j++)
{
if (arr[j] == target)
{
found = true; // מצאנו, זה יעצור את הלולאה מלהמשיך לחפש עבור איבר זה
}
}
// אם עבור איבר מסוים לא נמצא נגדי, המערך אינו מערך מראה
if (!found)
return false;
}
// אם עברנו את כל הבדיקות בהצלחה, סימן שהמערך אכן מערך מראה
return true;
}
//Q2 - א - END

