//Q3 - א - START
public static int[] DiceStatistics(int[] arr)
{
// הקצאת מערך מונים בגודל 21 - אינדקסים 0 עד 20
int[] counts = new int[21]; // מניחים איפוס של השפה או לולאה לאיפוס
// סריקת מערך ההטלות ועדכון המונים
for (int i = 0; i < arr.Length; i++)
{
int diceValue = arr[i]; // תוצאת ההטלה -ערך בין 1 ל-20
counts[diceValue]++;   // קידום המונה באינדקס המתאים
}
return counts;
}
//Q3 - א - END

//Q3 - ב - START
public static void PrintStatistics(int[] arr)
{
// חובה: זימון הפעולה מסעיף א' לקבלת מערך המונים
int[] counts = DiceStatistics(arr);
// --- חלק 1: מציאת והדפסת הערכים השכיחים ביותר ---
int maxCount = 0; // נניח בתחילה שהשכיחות המקסימלית היא של הפאה 1
// שלב א': מציאת השכיחות המרבית במערך המונים
for (int i = 1; i < counts.Length; i++)
{
if (counts[i] > maxCount)
{
maxCount = counts[i];
}
}
// שלב ב': הדפסת כל הערכים (האינדקסים) שזכו לשכיחות המרבית הזו
Console.Write("The most frequent values are: ");
for (int i = 1; i < counts.Length; i++)
{
if (counts[i] == maxCount)
{
Console.Write(i + " ");
}
}
Console.WriteLine();
// --- חלק 2: הדפסת ערכים שלא התקבלו כלל (מונה שווה ל-0) ---
Console.Write("Values that did not appear at all: ");
for (int i = 1; i < counts.Length; i++)
{
if (counts[i] == 0)
{
Console.Write(i + " ");
}
}
Console.WriteLine();
}
//Q3 - ב - END

