// Q5 – ב
// OPTION 1
public bool HandleNewWorkshop(Workshop ws)
{
// 1. לולאת חיפוש עד countWorkshops ולא עד סוף המערך
for (int i = 0; i < this.countWorkshops; i++)
{
// זימון נכון מסעיף א' על איבר מהמערך
if (this.workshops[i].IsSimilarWorkshop(ws))
{
// בדיקת תנאי הקיבולת באמצעות Get
if (this.workshops[i].GetPeople() + ws.GetPeople() <= 40)
{
// עדכון נכון בעזרת Set ו-Get
int totalPeople = this.workshops[i].GetPeople() + ws.GetPeople();
this.workshops[i].SetPeople(totalPeople);
return true; // עצירה והחזרה כשנמצא שילוב מתאים
}
}
}
// 2. תרחיש ב': לא נמצאה סדנה מתאימה לאיחוד, ננסה להוסיף חדשה
if (this.countWorkshops < 200) // בדיקה שהמערכת אינה מלאה (או < workshops.Length)
{
this.workshops[this.countWorkshops] = ws; // הוספה למקום הראשון הפנוי
this.countWorkshops++;                    // עדכון המונה
return true;
}
// 3. תרחיש ג': המערכת מלאה לחלוטין
return false;
}
//OPTION 2 (WHILE)
public bool HandleNewWorkshop(Workshop ws)
{
int i = 0;          bool joined = false;
// שלב 1: חיפוש סדנה דומה שיש בה מספיק מקום
while (i < this.countWorkshops && !joined)
{
// זימון הפעולה מסעיף א' לבדיקה האם הסדנאות דומות
if (this.workshops[i].IsSimilarWorkshop(ws))
{
// בדיקה האם סך המשתתפים אינו עולה על 40
if (this.workshops[i].GetPeople() + ws.GetPeople() <= 40)
{
// עדכון מספר המשתתפים בסדנה הקיימת
int updatedPeople = this.workshops[i].GetPeople() + ws.GetPeople();
this.workshops[i].SetPeople(updatedPeople);
joined = true; // סימון שנמצא פתרון, הלולאה תסתיים באופן טבעי
}
}
i++;
}
// אם הצלחנו לאחד את המשתתפים בסדנה קיימת, נחזיר true
if (joined)
return true;
// שלב 2: אם לא נמצאה סדנה מתאימה לאיחוד, ננסה להוסיף אותה כסדנה חדשה
if (this.countWorkshops < this.workshops.Length)        // אם יש מקום במערך
{
// הוספה למקום הראשון הפנוי
this.workshops[this.countWorkshops] = ws;
this.countWorkshops++; // עדכון מספר הסדנאות בפועל
return true;
}
// שלב 3: המערכת מלאה ולא ניתן לבצע איחוד או הוספה
return false;
}

